print(json.dumps(out))"}

{"code":"import json, re

def load_json(path_or_obj):
    if isinstance(path_or_obj, str) and path_or_obj.endswith('.json'):
        with open(path_or_obj, 'r', encoding='utf-8') as f:
            return json.load(f)
    return path_or_obj

pi = load_json(var_call_R5k3rCNJYAOPRqTsQePUQGj0)
texts = [r.get('Project_Information') for r in pi if isinstance(r.get('Project_Information'), str)]

# new name regex to handle 'The project is hosted on GitHub under the name X'
name_patterns = [
    re.compile(r"project\s+(?:is\s+hosted\s+on\s+GitHub\s+under\s+the\s+name|under\s+the\s+name)\s+([A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+)", re.I),
    re.compile(r"project\s+(?:named)\s+([A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+)", re.I),
    re.compile(r"project\s+([A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+)", re.I)
]

fork_patterns = [
    re.compile(r"\b([0-9][0-9,]*)\s+forks?\b", re.I),
    re.compile(r"forks?\s+count\s+of\s+([0-9][0-9,]*)", re.I),
    re.compile(r"forked\s+([0-9][0-9,]*)\s+times", re.I)
]

def extract_one(t):
    pname = None
    for p in name_patterns:
        m = p.search(t)
        if m:
            pname = m.group(1)
            break
    forks = None
    for p in fork_patterns:
        m = p.search(t)
        if m:
            forks = m.group(1)
            break
    return pname, forks

matches=[]
for t in texts[:5000]:
    pname, forks = extract_one(t)
    if pname and forks:
        matches.append({'name':pname,'forks':forks,'text':t[:180]})
        if len(matches)>=10:
            break

print('__RESULT__:')
print(json.dumps({'matches_found': len(matches), 'examples': matches}))"}

