    re.compile(r"forked\s+([0-9][0-9,]*)\s+times", re.I)
]

def extract_pi(t):
    if not isinstance(t, str):
        return None, None
    pname = None
    for p in name_patterns:
        m = p.search(t)
        if m:
            pname = m.group(1)
            break
